class Solution {
public:
TrieNode* root; // Initialize root pointer
bool isWordExist(string word) {
	TrieNode* pos = root;
	for (int i = word.size() - 1; i >= 0; i--) {
		int ch = word[i] - 'a';
		if (pos->children[ch] == nullptr) pos->children[ch] = new TrieNode(); // Initialize children array with new nodes if necessary
		pos = pos->children[ch];
	}
	bool res = true;
	pos = root;
	for (int i = word.size() - 1; i >= 0; i--) {
		int ch = word[i] - 'a';
		if (pos->children[ch] == nullptr || pos->children[ch]->isEnd == false) return false;
		pos = pos->children[ch];
	}
	return res;
}\n
